/* Blog Theme CSS */

/* Step 6: CSS Custom Properties */
:root {
    --primary-color: #0077cc;
    --text-color: #333;
    --bg-color: #f9f9f9;
    --accent-color: #005fa3;
}

/* Step 1: Foundation */
body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    font-size: 16px;
    line-height: 1.6;
    color: var(--text-color);
    background-color: var(--bg-color);
}

a {
    color: var(--primary-color);
    text-decoration: none;
}

h1 {
    font-size: 2rem;
    margin-bottom: 0.5rem;
    border-bottom: 3px solid var(--primary-color);
    padding-bottom: 0.3rem;
}

/* Step 2: Box Model */
*, *::before, *::after {
    box-sizing: border-box;
}

.container {
    max-width: 1100px;
    margin: 0 auto;
    padding: 0 20px;
}

.post {
    padding: 25px;
    margin-bottom: 30px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

/* Step 3: Borders and Radius */
.post img {
    border-radius: 6px;
    max-width: 100%;
}

/* Step 4: Typography */
h1, h2, h3 {
    font-family: Georgia, 'Times New Roman', serif;
    font-weight: 700;
    letter-spacing: 0.5px;
}

.post-meta {
    font-size: 0.85rem;
    color: #888;
    text-transform: uppercase;
}

blockquote {
    font-style: italic;
    border-left: 4px solid var(--accent-color);
    padding-left: 1rem;
    margin: 1rem 0;
    color: #555;
}

/* Step 5: Flexbox Navigation */
.nav {
    display: flex;
    justify-content: space-around;
    align-items: center;
    background-color: var(--primary-color);
    padding: 0;
}

.nav a {
    padding: 15px 20px;
    color: #fff;
    text-decoration: none;
}

.nav a:hover {
    background-color: rgba(255, 255, 255, 0.15);
}

/* Step 7: CSS Grid Layout */
.page-grid {
    /* TODO: Add display: grid, grid-template-columns, grid-gap */
}

.sidebar {
